void DisplayModule::timeout() {
  lv_subject_set_int(&subject_bluetooth, 0);
  lv_subject_copy_string(&subject_power_off, "");

  lv_obj_t *active = lv_screen_active();
  if (active != home_screen) {
    lv_screen_load(home_screen);
  }
  lv_timer_handler();
  lv_refr_now(NULL);
}

